import React, { useEffect, useState } from "react";
import axios from "axios";
import { useAuth } from "./context/AuthContext";

export default function DashboardAluno() {
  const { user } = useAuth();
  const [counts, setCounts] = useState({
    solicitacoes: 0,
    agendamentos: 0,
    atendidos: 0,
  });
  const [selected, setSelected] = useState(null);
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(false);

  // Definição dos cards
  const cards = [
    {
      key: "solicitacoes",
      label: "Minhas Solicitações",
      countField: "solicitacoes",
      endpoint: "/api/solicitacoes/me",
      statusFilter: null, // mostra todas
    },
    {
      key: "agendamentos",
      label: "Meus Agendamentos",
      countField: "agendamentos",
      endpoint: "/api/agendamentos/me",
      statusFilter: null,
    },
    {
      key: "atendidos",
      label: "Agendamentos Atendidos",
      countField: "atendidos",
      endpoint: "/api/agendamentos/me",
      statusFilter: "Atendido",
    },
  ];

  // Busca os totais para exibir nos cards
  useEffect(() => {
    // 1) Solicitações pendentes
    axios
      .get("/api/solicitacoes/me")
      .then((res) => {
        const pend = res.data.filter((s) => s.status === "Pendente").length;
        setCounts((c) => ({ ...c, solicitacoes: pend }));
      })
      .catch(() => {});

    // 2) Meus agendamentos e atendidos
    axios
      .get("/api/agendamentos/me")
      .then((res) => {
        const all = res.data;
        const proximos = all.length;
        const atend = all.filter((a) => a.status === "Atendido").length;
        setCounts((c) => ({
          ...c,
          agendamentos: proximos,
          atendidos: atend,
        }));
      })
      .catch(() => {});
  }, []);

  // Quando clica em um card, busca a lista correspondente
  const handleSelect = async (card) => {
    setSelected(card.key);
    setLoading(true);
    try {
      let lista = (await axios.get(card.endpoint)).data;
      if (card.statusFilter) {
        lista = lista.filter((i) => i.status === card.statusFilter);
      }
      setItems(lista);
    } catch (err) {
      console.error(err);
      setItems([]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto py-10 px-4">
      <h1 className="text-3xl font-bold mb-8">Olá, {user?.nome.split(" ")[0]}!</h1>

      {/* CARDS */}
      <div className="flex flex-col md:flex-row gap-6 mb-8">
        {cards.map((c) => (
          <button
            key={c.key}
            onClick={() => handleSelect(c)}
            className={`flex-1 p-6 rounded-2xl shadow transition ${
              selected === c.key
                ? "bg-[#D9E0FF]"
                : "bg-white hover:bg-gray-100"
            }`}
          >
            <div className="text-lg font-semibold mb-2">{c.label}</div>
            <div className="text-2xl font-bold text-[#3172C0]">
              {counts[c.countField]}
            </div>
          </button>
        ))}
      </div>

      {/* LISTA */}
      {loading && <p>Carregando...</p>}
      {!loading && selected && (
        <div className="bg-white rounded-2xl shadow p-6">
          <h2 className="text-xl font-semibold mb-4">
            {cards.find((c) => c.key === selected).label}
          </h2>
          <ul className="space-y-3">
            {items.length === 0 && (
              <li className="text-gray-500">Nenhum item encontrado.</li>
            )}
            {items.map((item) => (
              <li
                key={item.id}
                className="flex justify-between items-center bg-gray-50 rounded-xl px-5 py-3 shadow-sm"
              >
                {/* Data */}
                <span className="text-gray-800 font-medium">
                  {item.data
                    ? item.data.slice(0, 10).split("-").reverse().join("/")
                    : ""}
                </span>
                {/* Status */}
                <span
                  className={`px-3 py-1 rounded-full text-xs font-semibold ${
                    item.status === "Atendido"
                      ? "bg-green-100 text-green-800"
                      : item.status === "Pendente"
                      ? "bg-yellow-100 text-yellow-800"
                      : "bg-blue-100 text-blue-700"
                  }`}
                >
                  {item.status}
                </span>
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}
